 1	import type { FC } from 'react';
 2	import { ModalHOC } from 'src/modules/Providers/modals/ModalHOC/ModalHOC';
 3	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 4	import PlanStartMigrationModal from 'src/plans/actions/components/StartPlanModal/PlanStartMigrationModal';
 5	import PlanStatusLabel from 'src/plans/details/components/PlanStatus/PlanStatusLabel';
 6	import { PlanStatuses } from 'src/plans/details/components/PlanStatus/utils/types';
 7	import {
 8	  getCantStartVMStatusCount,
 9	  getMigrationVMsStatusCounts,
10	  getPlanStatus,
11	  isPlanArchived,
12	  isPlanExecuting,
13	} from 'src/plans/details/components/PlanStatus/utils/utils';
14	import VMStatusIconsRow from 'src/plans/details/components/PlanStatus/VMStatusIconsRow';
15	import { useForkliftTranslation } from 'src/utils/i18n';
16	
17	import { Button, ButtonVariant, Flex, FlexItem, Spinner, Split } from '@patternfly/react-core';
18	import { PlayIcon as StartIcon } from '@patternfly/react-icons';
19	import {
20	  getPlanVirtualMachines,
21	  getPlanVirtualMachinesMigrationStatus,
22	} from '@utils/crds/plans/selectors';
23	
24	import type { PlanFieldProps } from '../utils/types';
25	
26	import usePipelineTaskProgress from './hooks/usePipelineTaskProgress';
27	
28	import './PlanStatus.style.scss';
29	
30	const PlanStatus: FC<PlanFieldProps> = ({ plan }) => {
31	  const { t } = useForkliftTranslation();
32	  const { showModal } = useModal();
33	  const pipelinesProgressPercentage = usePipelineTaskProgress(plan);
34	  const planStatus = getPlanStatus(plan);
35	
36	  if (planStatus === PlanStatuses.Ready) {
37	    return (
38	      <Split hasGutter>
39	        <Button
40	          variant={ButtonVariant.secondary}
41	          icon={<StartIcon />}
42	          onClick={() => {
43	            showModal(<PlanStartMigrationModal plan={plan} title={t('Start')} />);
44	          }}
45	          isInline
46	          data-testid="plan-start-button-status"
47	        >
48	          {t('Start')}
49	        </Button>
50	      </Split>
51	    );
52	  }
53	
54	  const isPlanRunning = isPlanExecuting(plan) && !isPlanArchived(plan);
55	
56	  const vmStatuses =
57	    PlanStatuses.CannotStart === planStatus
58	      ? getCantStartVMStatusCount(getPlanVirtualMachines(plan))
59	      : getMigrationVMsStatusCounts(
60	          getPlanVirtualMachinesMigrationStatus(plan),
61	          getPlanVirtualMachinesMigrationStatus(plan).length,
62	          planStatus,
63	        );
64	
65	  return (
66	    <>
67	      <Flex
68	        direction={{ default: 'row' }}
69	        alignItems={{ default: 'alignItemsCenter' }}
70	        spaceItems={{ default: 'spaceItemsSm' }}
71	      >
72	        <FlexItem className="plan-status-cell-label-section">
73	          {isPlanRunning && PlanStatuses.Paused !== planStatus ? (
74	            <Split hasGutter>
75	              <Spinner size="md" data-testid="plan-progress-spinner" />
76	              <span className="pf-v6-u-font-size-sm" data-testid="plan-progress-percentage">
77	                {Math.trunc(pipelinesProgressPercentage)}%
78	              </span>
79	            </Split>
80	          ) : (
81	            <PlanStatusLabel plan={plan} />
82	          )}
83	        </FlexItem>
84	        <FlexItem>
85	          <ModalHOC>
86	            <VMStatusIconsRow plan={plan} statuses={vmStatuses} />
87	          </ModalHOC>
88	        </FlexItem>
89	      </Flex>
90	    </>
91	  );
92	};
93	
94	export default PlanStatus;

